import subprocess
from pathlib import Path

APP = Path('/app')

def write_tests():
    path = APP / 'internal/limiter/fairness_recovery_test.go'
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text('\npackage limiter\n\nimport (\n    "sync"\n    "testing"\n    "time"\n)\n\ntype manualClock struct {\n    mu  sync.Mutex\n    now time.Time\n}\n\nfunc newManualClock(now time.Time) *manualClock { return &manualClock{now: now} }\nfunc (c *manualClock) Now() time.Time {\n    c.mu.Lock()\n    defer c.mu.Unlock()\n    return c.now\n}\nfunc (c *manualClock) Set(now time.Time) {\n    c.mu.Lock()\n    c.now = now\n    c.mu.Unlock()\n}\nfunc (c *manualClock) Advance(delta time.Duration) {\n    c.mu.Lock()\n    c.now = c.now.Add(delta)\n    c.mu.Unlock()\n}\n\nfunc mustAllow(t *testing.T, limiter *Limiter, identity string) Decision {\n    t.Helper()\n    decision := limiter.Allow(identity)\n    if !decision.Allowed {\n        t.Fatalf("%q unexpectedly denied: %#v", identity, decision)\n    }\n    return decision\n}\n\nfunc mustDeny(t *testing.T, limiter *Limiter, identity string) Decision {\n    t.Helper()\n    decision := limiter.Allow(identity)\n    if decision.Allowed {\n        t.Fatalf("%q unexpectedly allowed: %#v", identity, decision)\n    }\n    if decision.RetryAfter <= 0 {\n        t.Fatalf("%q retry duration = %s, want positive", identity, decision.RetryAfter)\n    }\n    return decision\n}\n\nfunc TestExhaustedTenantDoesNotConsumeAnotherTenantBudget(t *testing.T) {\n    clock := newManualClock(time.Unix(1_700_000_000, 0))\n    traffic := New(1, 2, clock.Now)\n\n    mustAllow(t, traffic, "bulk-importer")\n    mustAllow(t, traffic, "bulk-importer")\n    mustDeny(t, traffic, "bulk-importer")\n\n    first := mustAllow(t, traffic, "clinic-sync")\n    if first.Remaining != 1 {\n        t.Fatalf("clinic-sync remaining = %d, want 1", first.Remaining)\n    }\n    mustAllow(t, traffic, "clinic-sync")\n    mustDeny(t, traffic, "clinic-sync")\n}\n\nfunc TestNormalizedTenantCannotEvadeItsBudget(t *testing.T) {\n    clock := newManualClock(time.Unix(1_700_000_000, 0))\n    traffic := New(1, 1, clock.Now)\n\n    mustAllow(t, traffic, "  Acme-Partner ")\n    mustDeny(t, traffic, "acme-partner")\n    mustDeny(t, traffic, "ACME-PARTNER  ")\n    mustAllow(t, traffic, "acme-partner-2")\n}\n\nfunc TestForwardTimeStillRefillsEachIdentity(t *testing.T) {\n    clock := newManualClock(time.Unix(1_700_000_000, 0))\n    traffic := New(2, 1, clock.Now)\n\n    mustAllow(t, traffic, "tenant-a")\n    mustDeny(t, traffic, "tenant-a")\n    clock.Advance(500 * time.Millisecond)\n    mustAllow(t, traffic, "tenant-a")\n\n    mustAllow(t, traffic, "tenant-b")\n    mustDeny(t, traffic, "tenant-b")\n    clock.Advance(500 * time.Millisecond)\n    mustAllow(t, traffic, "tenant-b")\n}\n\nfunc TestConcurrentFirstRequestsRemainTenantIsolated(t *testing.T) {\n    clock := newManualClock(time.Unix(1_700_000_000, 0))\n    traffic := New(0.5, 1, clock.Now)\n\n    const tenants = 64\n    start := make(chan struct{})\n    allowed := make(chan bool, tenants)\n    var wait sync.WaitGroup\n    for index := 0; index < tenants; index++ {\n        wait.Add(1)\n        go func(index int) {\n            defer wait.Done()\n            <-start\n            decision := traffic.Allow("tenant-" + time.Unix(int64(index), 0).Format("150405"))\n            allowed <- decision.Allowed\n        }(index)\n    }\n    close(start)\n    wait.Wait()\n    close(allowed)\n\n    count := 0\n    for decision := range allowed {\n        if decision {\n            count++\n        }\n    }\n    if count != tenants {\n        t.Fatalf("allowed first requests = %d, want %d", count, tenants)\n    }\n}\n', encoding='utf-8')
    path = APP / 'internal/limiter/time_safety_recovery_test.go'
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text('\npackage limiter\n\nimport (\n    "testing"\n    "time"\n)\n\nfunc TestBackwardClockDoesNotRefillOrMoveWatermark(t *testing.T) {\n    base := time.Unix(1_700_000_100, 0)\n    clock := newManualClock(base)\n    traffic := New(1, 1, clock.Now)\n\n    mustAllow(t, traffic, "tenant-a")\n    clock.Set(base.Add(-30 * time.Second))\n    mustDeny(t, traffic, "tenant-a")\n    clock.Set(base.Add(-5 * time.Second))\n    mustDeny(t, traffic, "tenant-a")\n\n    clock.Set(base.Add(500 * time.Millisecond))\n    mustDeny(t, traffic, "tenant-a")\n    clock.Set(base.Add(1100 * time.Millisecond))\n    mustAllow(t, traffic, "tenant-a")\n}\n\nfunc TestRepeatedBackwardSamplesNeverMintAllowance(t *testing.T) {\n    base := time.Unix(1_700_000_200, 0)\n    clock := newManualClock(base)\n    traffic := New(4, 2, clock.Now)\n\n    mustAllow(t, traffic, "tenant-a")\n    mustAllow(t, traffic, "tenant-a")\n    for _, delta := range []time.Duration{-time.Second, -20 * time.Second, -2 * time.Second, -45 * time.Second} {\n        clock.Set(base.Add(delta))\n        mustDeny(t, traffic, "tenant-a")\n    }\n\n    mustAllow(t, traffic, "tenant-b")\n    mustAllow(t, traffic, "tenant-b")\n    mustDeny(t, traffic, "tenant-b")\n}\n\nfunc TestForwardFractionalRefillAndRetryDuration(t *testing.T) {\n    base := time.Unix(1_700_000_300, 0)\n    clock := newManualClock(base)\n    traffic := New(2, 1, clock.Now)\n\n    mustAllow(t, traffic, "tenant-a")\n    clock.Set(base.Add(250 * time.Millisecond))\n    denied := mustDeny(t, traffic, "tenant-a")\n    if denied.RetryAfter != 250*time.Millisecond {\n        t.Fatalf("retry duration = %s, want 250ms", denied.RetryAfter)\n    }\n\n    clock.Set(base.Add(500 * time.Millisecond))\n    mustAllow(t, traffic, "tenant-a")\n}\n', encoding='utf-8')

def test_recovery_contracts():
    write_tests()
    result = subprocess.run(
        ['/usr/local/go/bin/go', 'test', '-race', './internal/limiter', '-count=1'],
        cwd=APP, text=True, stdout=subprocess.PIPE, stderr=subprocess.STDOUT, timeout=120,
    )
    assert result.returncode == 0, result.stdout
